-- RoyallAzz MVP — Unified Schema

create extension if not exists "pgcrypto";

-- MERCHANTS
create table public.merchants (
  id uuid primary key references auth.users(id) on delete cascade,
  email text not null unique,
  business_name text not null,
  logo_url text,
  plan text not null default 'free' check (plan in ('free', 'pro', 'business')),
  stripe_customer_id text,
  created_at timestamptz not null default now()
);

-- LOYALTY PROGRAMS
create table public.loyalty_programs (
  id uuid primary key default gen_random_uuid(),
  merchant_id uuid not null references public.merchants(id) on delete cascade,
  name text not null,
  type text not null check (type in ('stamp', 'points')),
  target int not null check (target > 0),
  welcome_bonus int not null default 0 check (welcome_bonus >= 0),
  is_active boolean not null default true,
  created_at timestamptz not null default now()
);
create index idx_programs_merchant on public.loyalty_programs(merchant_id);

-- REWARDS
create table public.rewards (
  id uuid primary key default gen_random_uuid(),
  program_id uuid not null references public.loyalty_programs(id) on delete cascade,
  name text not null,
  discount_type text not null check (discount_type in ('percentage', 'fixed', 'freebie')),
  discount_value numeric not null default 0,
  is_active boolean not null default true,
  created_at timestamptz not null default now()
);
create index idx_rewards_program on public.rewards(program_id);

-- CUSTOMERS
create table public.customers (
  id uuid primary key references auth.users(id) on delete cascade,
  email text not null,
  full_name text,
  phone text,
  created_at timestamptz not null default now()
);

-- CUSTOMER CARDS
create table public.customer_cards (
  id uuid primary key default gen_random_uuid(),
  customer_id uuid not null references public.customers(id) on delete cascade,
  program_id uuid not null references public.loyalty_programs(id) on delete cascade,
  balance int not null default 0 check (balance >= 0),
  tier text not null default 'bronze' check (tier in ('bronze', 'silver', 'gold', 'vip')),
  created_at timestamptz not null default now(),
  unique(customer_id, program_id)
);
create index idx_cards_customer on public.customer_cards(customer_id);
create index idx_cards_program on public.customer_cards(program_id);

-- TRANSACTIONS
create table public.transactions (
  id uuid primary key default gen_random_uuid(),
  card_id uuid not null references public.customer_cards(id) on delete cascade,
  merchant_id uuid not null references public.merchants(id),
  type text not null check (type in ('earn', 'redeem')),
  amount int not null,
  source text not null default 'qr' check (source in ('qr', 'nfc', 'manual', 'api')),
  created_at timestamptz not null default now()
);
create index idx_txn_card on public.transactions(card_id);
create index idx_txn_merchant on public.transactions(merchant_id);
create index idx_txn_created on public.transactions(created_at desc);

-- MERCHANT QR CODES
create table public.merchant_qr_codes (
  id uuid primary key default gen_random_uuid(),
  merchant_id uuid not null references public.merchants(id) on delete cascade,
  program_id uuid not null references public.loyalty_programs(id) on delete cascade,
  qr_url text not null,
  is_active boolean not null default true,
  created_at timestamptz not null default now()
);

-- CUSTOMER QR CODES
create table public.customer_qr_codes (
  id uuid primary key default gen_random_uuid(),
  customer_id uuid not null references public.customers(id) on delete cascade,
  secret_key text not null unique default encode(gen_random_bytes(32), 'hex'),
  is_active boolean not null default true,
  created_at timestamptz not null default now()
);

-- RLS
alter table public.merchants enable row level security;
alter table public.loyalty_programs enable row level security;
alter table public.rewards enable row level security;
alter table public.customers enable row level security;
alter table public.customer_cards enable row level security;
alter table public.transactions enable row level security;
alter table public.merchant_qr_codes enable row level security;
alter table public.customer_qr_codes enable row level security;

create policy "merchants_own" on public.merchants for all using (id = auth.uid());
create policy "programs_merchant_all" on public.loyalty_programs for all using (merchant_id = auth.uid());
create policy "programs_public_read" on public.loyalty_programs for select using (is_active = true);
create policy "rewards_merchant_all" on public.rewards for all
  using (program_id in (select id from public.loyalty_programs where merchant_id = auth.uid()));
create policy "rewards_public_read" on public.rewards for select using (is_active = true);
create policy "customers_own" on public.customers for all using (id = auth.uid());
create policy "cards_customer" on public.customer_cards for all using (customer_id = auth.uid());
create policy "cards_merchant_read" on public.customer_cards for select
  using (program_id in (select id from public.loyalty_programs where merchant_id = auth.uid()));
create policy "txn_customer" on public.transactions for select
  using (card_id in (select id from public.customer_cards where customer_id = auth.uid()));
create policy "txn_merchant" on public.transactions for all using (merchant_id = auth.uid());
create policy "mqr_merchant" on public.merchant_qr_codes for all using (merchant_id = auth.uid());
create policy "mqr_public_read" on public.merchant_qr_codes for select using (is_active = true);
create policy "cqr_customer" on public.customer_qr_codes for all using (customer_id = auth.uid());

-- PLAN ENFORCEMENT
create or replace function public.check_plan_limit(p_merchant_id uuid)
returns boolean language plpgsql security definer as $$
declare
  v_plan text;
  v_count int;
begin
  select plan into v_plan from public.merchants where id = p_merchant_id;
  select count(*) into v_count from public.loyalty_programs where merchant_id = p_merchant_id;
  if v_plan = 'free' and v_count >= 1 then return false; end if;
  if v_plan = 'pro' and v_count >= 5 then return false; end if;
  return true;
end;
$$;
