'use client';

import { useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';

export default function LoginPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const redirect = searchParams.get('redirect') || '/merchant';
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const supabase = createClient();
    const { error: authError } = await supabase.auth.signInWithPassword({ email, password });
    if (authError) {
      setError(authError.message);
      setLoading(false);
      return;
    }
    router.push(redirect);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[var(--bg-base)] px-4">
      <div className="w-full max-w-sm space-y-6 page-enter">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">
            <span>Royall</span><span className="text-[var(--accent)]">Azz</span>
          </h1>
          <p className="text-[13px] text-[var(--text-tertiary)] mt-1">Connectez-vous à votre espace</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <Input label="Email" type="email" value={email} onChange={e => setEmail(e.target.value)} required placeholder="merchant@example.com" />
          <Input label="Mot de passe" type="password" value={password} onChange={e => setPassword(e.target.value)} required placeholder="••••••••" />
          {error && <p className="text-[12px] text-[var(--error)]">{error}</p>}
          <Button type="submit" loading={loading} className="w-full">Se connecter</Button>
        </form>

        <p className="text-center text-[13px] text-[var(--text-tertiary)]">
          Pas encore de compte ?{' '}
          <a href="/register" className="text-[var(--accent)] hover:underline">Créer un compte</a>
        </p>
      </div>
    </div>
  );
}
```

IMPORTANT: Login uses `useSearchParams()` which requires Suspense boundary. Wrap the component in a Suspense, or pass searchParams as a prop. The simplest approach is to wrap the login content in a separate client component and have the page wrap it in Suspense.

