'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';

export default function RegisterPage() {
  const router = useRouter();
  const [form, setForm] = useState({ email: '', password: '', businessName: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const update = (key: string, value: string) => setForm(prev => ({ ...prev, [key]: value }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const supabase = createClient();

    const { data, error: signUpError } = await supabase.auth.signUp({
      email: form.email,
      password: form.password,
    });

    if (signUpError) { setError(signUpError.message); setLoading(false); return; }

    if (data.user) {
      const { error: insertError } = await supabase.from('merchants').insert({
        id: data.user.id,
        email: form.email,
        business_name: form.businessName,
      });
      if (insertError) { setError(insertError.message); setLoading(false); return; }
    }

    router.push('/merchant');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[var(--bg-base)] px-4">
      <div className="w-full max-w-sm space-y-6 page-enter">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-[var(--text-primary)]">
            <span>Royall</span><span className="text-[var(--accent)]">Azz</span>
          </h1>
          <p className="text-[13px] text-[var(--text-tertiary)] mt-1">Créez votre espace marchand</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <Input label="Nom du commerce" value={form.businessName} onChange={e => update('businessName', e.target.value)} required placeholder="Ma Boutique" />
          <Input label="Email" type="email" value={form.email} onChange={e => update('email', e.target.value)} required placeholder="merchant@example.com" />
          <Input label="Mot de passe" type="password" value={form.password} onChange={e => update('password', e.target.value)} required placeholder="Min. 6 caractères" minLength={6} />
          {error && <p className="text-[12px] text-[var(--error)]">{error}</p>}
          <Button type="submit" loading={loading} className="w-full">Créer mon compte</Button>
        </form>

        <p className="text-center text-[13px] text-[var(--text-tertiary)]">
          Déjà un compte ?{' '}
          <a href="/login" className="text-[var(--accent)] hover:underline">Se connecter</a>
        </p>
      </div>
    </div>
  );
}
