          cookiesToSet.forEach(({ name, value, options }) => {
            try {
              cookieStore.set(name, value, options);
            } catch {
              // setAll is called from Server Component context where
              // cookies cannot be modified — safe to ignore.
            }
          });
        },
      },
    },
  );
}

