-- Plan enforcement: checks if a merchant can create more loyalty programs
create or replace function public.check_plan_limit(p_merchant_id uuid)
returns boolean language plpgsql security definer as $$
declare
  v_plan text;
  v_count int;
begin
  select plan into v_plan from public.merchants where id = p_merchant_id;
  select count(*) into v_count from public.loyalty_programs where merchant_id = p_merchant_id;

  if v_plan = 'free' and v_count >= 1 then return false; end if;
  if v_plan = 'pro' and v_count >= 5 then return false; end if;

  -- business plan: unlimited
  return true;
end;
$$;

import { createServerClient } from '@supabase/ssr';
import { NextResponse, type NextRequest } from 'next/server';

const PUBLIC_PATHS = ['/login', '/register', '/scan'];

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Allow public paths and root landing page
  if (PUBLIC_PATHS.some((p) => pathname.startsWith(p)) || pathname === '/') {
    return NextResponse.next();
  }

  let response = NextResponse.next({ request });

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll();
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value }) =>
            request.cookies.set(name, value),
          );
          response = NextResponse.next({ request });
          cookiesToSet.forEach(({ name, value, options }) =>
            response.cookies.set(name, value, options),
          );
        },
      },
    },
  );

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    const url = request.nextUrl.clone();
    url.pathname = '/login';
    url.searchParams.set('redirect', pathname);
    return NextResponse.redirect(url);
  }

  return response;
}

